def transition(state, action):
    s = dict(state)
    chargers = [dict(c) for c in s.get("chargers", [])]
    queue = [dict(v) for v in s.get("queue", [])]
    name = action.get("name")

    load_limit = s.get("load_limit", 0)
    default_rate = s.get("default_rate", 0)
    throttled_rate = s.get("throttled_rate", 0)
    step_soc = s.get("charge_step_soc", 0)

    if name == "plug":
        # Connect the next waiting vehicle to the first free charger. No power
        # is drawn yet (rate 0); a later `charge` energizes it.
        free_idx = -1
        for i, c in enumerate(chargers):
            if c.get("vehicle") is None:
                free_idx = i
                break
        if free_idx >= 0 and queue:
            v = queue.pop(0)
            chargers[free_idx] = {
                "vehicle": v.get("id"),
                "soc": v.get("soc", 0),
                "target": v.get("target", 100),
                "rate": 0,
                "throttled": False,
            }

    elif name == "charge":
        # Advance one time step. Each occupied, not-yet-full charger requests its
        # rate (throttled_rate if throttled, else default_rate). Rates are granted
        # in charger order so the station total never exceeds load_limit; a charger
        # that does not fully fit the remaining capacity gets only what is left.
        # State of charge rises in proportion to the granted rate, capped at target.
        remaining = load_limit
        for c in chargers:
            if c.get("vehicle") is None:
                c["rate"] = 0
                continue
            soc = c.get("soc", 0)
            target = c.get("target", 100)
            if soc >= target:
                c["rate"] = 0
                continue
            want = throttled_rate if c.get("throttled") else default_rate
            give = want if want <= remaining else remaining
            if give < 0:
                give = 0
            c["rate"] = give
            remaining = remaining - give
            if give > 0 and default_rate > 0:
                inc = int(round(give * step_soc / default_rate))
                new_soc = soc + inc
                c["soc"] = target if new_soc > target else new_soc
        s["time"] = s.get("time", 0) + 1

    elif name == "throttle":
        # Cap every occupied charger at throttled_rate, lowering the station's
        # total load so more cars fit under load_limit. Does not advance time.
        for c in chargers:
            if c.get("vehicle") is not None:
                c["throttled"] = True
                if c.get("rate", 0) > throttled_rate:
                    c["rate"] = throttled_rate

    elif name == "unplug":
        # Disconnect a finished car (soc >= target) if one exists, else the first
        # occupied charger (an early departure). Free the bay and count a vehicle
        # served only if it left at or above its target.
        idx = -1
        for i, c in enumerate(chargers):
            if c.get("vehicle") is not None and c.get("soc", 0) >= c.get("target", 100):
                idx = i
                break
        if idx < 0:
            for i, c in enumerate(chargers):
                if c.get("vehicle") is not None:
                    idx = i
                    break
        if idx >= 0:
            c = chargers[idx]
            if c.get("soc", 0) >= c.get("target", 100):
                s["served"] = s.get("served", 0) + 1
            chargers[idx] = {"vehicle": None, "soc": 0, "target": 0,
                             "rate": 0, "throttled": False}

    # noop / unknown action: state passes through unchanged.

    s["chargers"] = chargers
    s["queue"] = queue
    s["total_load"] = sum(c.get("rate", 0) for c in chargers)
    return s

