def perceive(data):
    cars = []
    for item in data.get("arrivals", []):
        cars.append({
            "id": str(item.get("id")),
            "soc": int(item.get("soc", 0)),
            "target": int(item.get("target", 100)),
        })
    return {"queue": cars}
